package com.airlock.saas.base.domain.model.saasconfig

import com.airlock.saas.base.domain.model.ValidationWithException.inContentType
import com.airlock.saas.base.domain.model.ValidationWithException.isNotEmpty
import com.airlock.saas.base.domain.model.ValidationWithException.notLargerThan
import com.airlock.saas.base.domain.model.exceptions.DomainValidationException.Companion.invalidFileType
import java.util.Base64

sealed interface UiImage {
	val contentType: ContentType
	val data: ByteArray

	fun getBase64(): String = Base64.getEncoder().encodeToString(data)
}

class Favicon(override val contentType: ContentType, override val data: ByteArray, pointer: String? = null) : UiImage {

	init {
		inContentType(contentType, pointer ?: "", ALLOWED_FAVICON_MIME_TYPES)
		notLargerThan(data, pointer ?: "", MAX_FILE_SIZE_BYTES)
		isNotEmpty(data, pointer ?: "")
	}

	companion object {
		private val ALLOWED_FAVICON_MIME_TYPES = arrayOf(
			ContentType.PNG,
			ContentType.SVG,
			ContentType.X_ICON,
			ContentType.VND_ICON,
		)
	}
}

class Logo(override val contentType: ContentType, override val data: ByteArray, pointer: String? = null) : UiImage {

	init {
		inContentType(contentType, pointer ?: "", ALLOWED_LOGO_MIME_TYPES)
		notLargerThan(data, pointer ?: "", MAX_FILE_SIZE_BYTES)
		isNotEmpty(data, pointer ?: "")
	}

	companion object {
		private val ALLOWED_LOGO_MIME_TYPES = arrayOf(
			ContentType.PNG,
			ContentType.SVG,
			ContentType.JPEG,
		)
	}
}

enum class ContentType(val value: String) {
	PNG("image/png"),
	SVG("image/svg+xml"),
	JPEG("image/jpeg"),
	X_ICON("image/x-icon"),
	VND_ICON("image/vnd.microsoft.icon"),
	;

	companion object {
		fun fromString(value: String, pointer: String? = null): ContentType =
			entries.singleOrNull { it.value == value } ?: throw invalidFileType(pointer ?: "")
	}

	fun getFileExtension(): String =
		when (this) {
			PNG -> "png"
			SVG -> "svg"
			JPEG -> "jpeg"
			X_ICON -> "ico"
			VND_ICON -> "ico"
		}
}

private const val MAX_FILE_SIZE_BYTES: Long = 512 * 1024 // 512KB

